function isIncidentShape(value) {
  return (
    value &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    ("severity" in value || "category" in value || "action" in value)
  );
}

function collectStrings(value, result = []) {
  if (typeof value === "string") {
    const trimmed = value.trim();
    if (trimmed) result.push(trimmed);
    return result;
  }

  if (Array.isArray(value)) {
    for (const item of value) collectStrings(item, result);
    return result;
  }

  if (value && typeof value === "object") {
    for (const nested of Object.values(value)) collectStrings(nested, result);
  }

  return result;
}

function findIncidentObject(value) {
  if (isIncidentShape(value)) return value;

  if (Array.isArray(value)) {
    for (const item of value) {
      const found = findIncidentObject(item);
      if (found) return found;
    }
    return null;
  }

  if (value && typeof value === "object") {
    for (const nested of Object.values(value)) {
      const found = findIncidentObject(nested);
      if (found) return found;
    }
  }

  return null;
}

const directIncident = findIncidentObject($json);
let parsed = null;

if (directIncident) {
  parsed = directIncident;
} else {
  const rawCandidates = collectStrings($json);

  for (const raw of rawCandidates) {
    const fencedMatch = raw.match(/```(?:json)?\s*([\s\S]*?)```/i);
    const jsonText = fencedMatch?.[1]?.trim() || raw.match(/\{[\s\S]*\}/)?.[0] || "";

    if (!jsonText) continue;

    try {
      const candidate = JSON.parse(jsonText);
      if (isIncidentShape(candidate)) {
        parsed = candidate;
        break;
      }
    } catch {}
  }
}

if (!parsed) {
  return {
    success: false,
    category: "Parse Error",
    severity: "Low",
    action: "AI returned unreadable format. Check n8n execution logs.",
    shouldNotifySlack: false
  };
}

const severityRaw = String(parsed.severity || "")
  .trim()
  .toLowerCase()
  .replace(/[^\w]/g, "");

const severityMap = {
  low: "Low",
  medium: "Medium",
  high: "High"
};

const severity = severityMap[severityRaw] || "Low";
const category = String(parsed.category || "General").trim() || "General";
const action =
  String(parsed.action || "No specific action recommended").trim() ||
  "No specific action recommended";

return {
  success: true,
  category,
  severity,
  action,
  shouldNotifySlack: severity === "High"
};
